import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class LogoutController {

    private static final String[] ALLOWED_REDIRECTS = {
        "/dashboard",
        "/home",
        "/login"
    };

    @GetMapping("/logout")
    public void logout(@RequestParam(required = false) String next, javax.servlet.http.HttpServletRequest request, javax.servlet.http.HttpServletResponse response) throws Exception {
        if (next != null && isValidRedirect(next)) {
            response.sendRedirect(request.getContextPath() + next);
        } else {
            response.sendRedirect(request.getContextPath() + "/login");
        }
    }

    private boolean isValidRedirect(String redirectUrl) {
        for (String allowedRedirect : ALLOWED_REDIRECTS) {
            if (redirectUrl.equals(allowedRedirect)) {
                return true;
            }
        }
        return false;
    }
}